previewCss:
.darma-loader-darma-custom-503 {color: var(--loader-color, #ca8a04);
  --loader-secondary-color: var(--loader-secondary-color, #fde047);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 70px;
   aspect-ratio: 1;
   --c:var(--loader-color, #ca8a04) 98%,#0000;
   background: radial-gradient(50% 70% at 50% 120%, var(--c)) top, radial-gradient(70% 50% at -20% 50%, var(--c)) right, radial-gradient(50% 70% at 50% -20%, var(--c)) bottom, radial-gradient(70% 50% at 120% 50%, var(--c)) left;
   background-size: 100% 50.1%,50.1% 100%;
   background-repeat: no-repeat;
   -webkit-mask: radial-gradient(circle 5px,#0000 90%,currentColor);
   animation: darma-loader-darma-custom-503-l9 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-503-l9  {
  100%{transform: rotate(1turn)}
}

